async function runAudit() {
  const target = await getTargetSite();
  const result = await auditSite({ siteUrl: target.siteUrl });
  return {
    siteUrl: result.siteUrl,
    findings: result.findings,
    summary: result.summary
  };
}

runAudit().then(result => console.log(JSON.stringify(result)));

